import json, re, statistics
import math
from pathlib import Path
# Load clinical LGG records from var_call_GaH0hRfrxzROsI4cvqo8ttaP (file path)
clinical_path = var_call_GaH0hRfrxzROsI4cvqo8ttaP
with open(clinical_path, 'r') as f:
    clinical = json.load(f)
# Load RNASeq IGF2 records from var_call_Z0LcWu3tQvIgLrUClKoQp9rX (this is a list)
rna = var_call_Z0LcWu3tQvIgLrUClKoQp9rX
# Extract ParticipantBarcode from Patient_description
pattern = re.compile(r'(TCGA-[A-Za-z0-9-]+-[A-Za-z0-9]+)')
clin_rows = []
for rec in clinical:
    pd = rec.get('Patient_description','')
    m = pattern.search(pd)
    if not m:
        continue
    barcode = m.group(1)
    hist = rec.get('histological_type')
    # exclude histological_type enclosed in square brackets
    if hist is None:
        continue
    if isinstance(hist, str) and re.match(r'^\[.*\]$', hist.strip()):
        continue
    # keep
    clin_rows.append({'ParticipantBarcode': barcode, 'histological_type': hist})
# Build lookup from barcode to histology (one-to-many if duplicates; keep first?)
# There may be multiple clinical records per barcode; prefer first occurrence
barcode_to_hist = {}
for r in clin_rows:
    if r['ParticipantBarcode'] not in barcode_to_hist:
        barcode_to_hist[r['ParticipantBarcode']] = r['histological_type']
# Process RNA records: convert normalized_count to float, filter valid
rna_rows = []
for rec in rna:
    pb = rec.get('ParticipantBarcode')
    nc = rec.get('normalized_count')
    if nc is None:
        continue
    try:
        val = float(nc)
    except Exception:
        continue
    # keep only if participant in LGG clinical barcodes
    if pb in barcode_to_hist:
        rna_rows.append({'ParticipantBarcode': pb, 'normalized_count': val, 'histological_type': barcode_to_hist[pb]})
# If no matches, attempt matching by first 12 chars? Many TCGA barcodes are like TCGA-XX-XXXX; ensure consistency
if len(rna_rows) == 0:
    # attempt matching by first 7 characters (TCGA-XX)
    for rec in rna:
        pb = rec.get('ParticipantBarcode')
        nc = rec.get('normalized_count')
        if nc is None:
            continue
        try:
            val = float(nc)
        except Exception:
            continue
        # try to find any clinical barcode that startswith pb prefix
        for clin_pb, hist in barcode_to_hist.items():
            if clin_pb.startswith(pb.split('-')[0]) or pb.startswith(clin_pb.split('-')[0]):
                rna_rows.append({'ParticipantBarcode': clin_pb, 'normalized_count': val, 'histological_type': hist})
# Compute log10(normalized_count + 1) grouped by histology
from collections import defaultdict
group_vals = defaultdict(list)
for r in rna_rows:
    val = r['normalized_count']
    if val is None:
        continue
    # skip negative values
    if val < 0:
        continue
    lg = math.log10(val + 1.0)
    group_vals[r['histological_type']].append(lg)
# Compute means with at least 4 decimal places
result = {}
for hist, vals in group_vals.items():
    if len(vals) == 0:
        continue
    mean_val = sum(vals)/len(vals)
    # format to at least 4 decimal places, keep as float
    result[hist] = float(f"{mean_val:.4f}")
# Sort result by histology name for consistent output
sorted_result = {k: result[k] for k in sorted(result.keys())}
print("__RESULT__:")
print(json.dumps(sorted_result))

