import json, math, re
# Load full RNA IGF2 results from var_call_utoPbKretOG4ILzz6UoB1cgv (file path)
rna_path = var_call_utoPbKretOG4ILzz6UoB1cgv
with open(rna_path, 'r') as f:
    rna = json.load(f)
# Load clinical LGG records from var_call_GaH0hRfrxzROsI4cvqo8ttaP (file path)
clin_path = var_call_GaH0hRfrxzROsI4cvqo8ttaP
with open(clin_path, 'r') as f:
    clinical = json.load(f)
# Build barcode to histology mapping from clinical
pattern = re.compile(r'(TCGA-[A-Za-z0-9-]+-[A-Za-z0-9]+)')
barcode_to_hist = {}
for rec in clinical:
    pd = rec.get('Patient_description','')
    m = pattern.search(pd)
    if not m:
        continue
    barcode = m.group(1)
    hist = rec.get('histological_type')
    if hist is None:
        continue
    if isinstance(hist, str) and re.match(r'^\[.*\]$', hist.strip()):
        continue
    if barcode not in barcode_to_hist:
        barcode_to_hist[barcode] = hist
# Now match RNA records to clinical by exact ParticipantBarcode
from collections import defaultdict
group_vals = defaultdict(list)
for rec in rna:
    pb = rec.get('ParticipantBarcode')
    nc = rec.get('normalized_count')
    if nc is None or pb is None:
        continue
    try:
        val = float(nc)
    except:
        continue
    # if pb exactly in mapping
    if pb in barcode_to_hist:
        hist = barcode_to_hist[pb]
        if val >= 0:
            group_vals[hist].append(math.log10(val+1))
# If some clinical barcodes might be shortened (e.g., participant barcode with last block shorter), try matching by first 12 chars (TCGA-XX-XXXX)
if len(group_vals) == 0:
    # create mapping by first 12 chars
    short_to_hist = {}
    for k,v in barcode_to_hist.items():
        short = k[:12]
        if short not in short_to_hist:
            short_to_hist[short] = v
    for rec in rna:
        pb = rec.get('ParticipantBarcode')
        nc = rec.get('normalized_count')
        if nc is None or pb is None:
            continue
        try:
            val = float(nc)
        except:
            continue
        short = pb[:12]
        if short in short_to_hist:
            hist = short_to_hist[short]
            if val >= 0:
                group_vals[hist].append(math.log10(val+1))
# Prepare final results with >=4 decimal places
results = {}
for hist, vals in group_vals.items():
    if len(vals) == 0:
        continue
    mean_val = sum(vals)/len(vals)
    results[hist] = float(f"{mean_val:.4f}")
# Sort results
sorted_results = {k: results[k] for k in sorted(results.keys())}
print("__RESULT__:")
print(json.dumps(sorted_results))

